 1	import * as React from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 6	import SnapshotModal from '@kubevirt-utils/components/SnapshotModal/SnapshotModal';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { isEmpty } from '@kubevirt-utils/utils/utils';
 9	import {
10	  Bullseye,
11	  Button,
12	  ButtonVariant,
13	  Card,
14	  CardBody,
15	  CardFooter,
16	  CardTitle,
17	  Divider,
18	  Label,
19	} from '@patternfly/react-core';
20	
21	import useSnapshotData from '../../../snapshots/hooks/useSnapshotData';
22	import { createURL } from '../../utils/utils';
23	
24	import VirtualMachinesOverviewTabSnapshotsRow from './VirtualMachinesOverviewTabSnapshotsRow';
25	
26	import './virtual-machines-overview-tab-snapshots.scss';
27	
28	type VirtualMachinesOverviewTabSnapshotsProps = {
29	  vm: V1VirtualMachine;
30	};
31	
32	const VirtualMachinesOverviewTabSnapshots: React.FC<VirtualMachinesOverviewTabSnapshotsProps> = ({
33	  vm,
34	}) => {
35	  const { t } = useKubevirtTranslation();
36	  const { snapshots } = useSnapshotData(vm?.metadata?.name, vm?.metadata?.namespace);
37	  const { createModal } = useModal();
38	  const snapshotsTabLink = createURL('snapshots', location?.pathname);
39	
40	  return (
41	    <div
42	      className="VirtualMachinesOverviewTabSnapshots--main"
43	      data-test-id="virtual-machine-overview-snapshots"
44	    >
45	      <Card>
46	        <CardTitle className="text-muted">
47	          <Link to={snapshotsTabLink}>
48	            {t('Snapshots ({{snapshots}})', { snapshots: snapshots.length || 0 })}
49	          </Link>
50	
51	          <Button
52	            isInline
53	            onClick={() => createModal((props) => <SnapshotModal vm={vm} {...props} />)}
54	            variant={ButtonVariant.link}
55	          >
56	            {t('Take snapshot')}
57	          </Button>
58	        </CardTitle>
59	        <Divider />
60	        <CardBody isFilled>
61	          {!isEmpty(snapshots) ? (
62	            snapshots?.map((snapshot) => (
63	              <VirtualMachinesOverviewTabSnapshotsRow
64	                key={snapshot?.metadata?.uid}
65	                snapshot={snapshot}
66	                vm={vm}
67	              />
68	            ))
69	          ) : (
70	            <Bullseye>{t('No snapshots found')}</Bullseye>
71	          )}
72	        </CardBody>
73	        {!isEmpty(snapshots) && (
74	          <CardFooter>
75	            <Link to={snapshotsTabLink}>
76	              <Label color="blue" variant="outline">
77	                {t('View More')}
78	              </Label>
79	            </Link>
80	          </CardFooter>
81	        )}
82	      </Card>
83	    </div>
84	  );
85	};
86	
87	export default VirtualMachinesOverviewTabSnapshots;

